import{_ as a,c as i,o,a5 as t}from"./chunks/framework.Dtwt352Q.js";const g=JSON.parse('{"title":"Privacy Policy","description":"Privacy policy for the OpenCode Chinese tutorial website, explaining how we collect, use, and protect your information.","frontmatter":{"title":"Privacy Policy","description":"Privacy policy for the OpenCode Chinese tutorial website, explaining how we collect, use, and protect your information."},"headers":[],"relativePath":"en/privacy.md","filePath":"en/privacy.md","lastUpdated":1772014034000}'),r={name:"en/privacy.md"};function l(n,e,s,c,h,d){return o(),i("div",null,[...e[0]||(e[0]=[t('<div class="privacy-page"><h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to “Privacy Policy”">​</a></h1><p>Last updated: January 2026</p><p>This privacy policy explains how OpenCode Chinese Tutorial (learnopencode.com, hereinafter referred to as &quot;this site&quot;) collects, uses, and protects your information.</p><h2 id="information-collection" tabindex="-1">Information Collection <a class="header-anchor" href="#information-collection" aria-label="Permalink to “Information Collection”">​</a></h2><h3 id="automatically-collected-information" tabindex="-1">Automatically Collected Information <a class="header-anchor" href="#automatically-collected-information" aria-label="Permalink to “Automatically Collected Information”">​</a></h3><p>When you visit this site, we may automatically collect the following information through third-party services:</p><ul><li><strong>Device Information</strong>: Browser type, operating system, screen resolution</li><li><strong>Visit Information</strong>: Visit time, page view history, referring website</li><li><strong>Network Information</strong>: IP address (used for approximate geographic location)</li></ul><h3 id="cookies-and-similar-technologies" tabindex="-1">Cookies and Similar Technologies <a class="header-anchor" href="#cookies-and-similar-technologies" aria-label="Permalink to “Cookies and Similar Technologies”">​</a></h3><p>This site uses cookies and similar technologies to:</p><ul><li>Remember your preference settings (such as dark/light theme)</li><li>Analyze website traffic and usage</li><li>Display relevant advertisements</li></ul><h2 id="third-party-services" tabindex="-1">Third-Party Services <a class="header-anchor" href="#third-party-services" aria-label="Permalink to “Third-Party Services”">​</a></h2><p>This site uses the following third-party services, which have their own privacy policies:</p><h3 id="google-adsense" tabindex="-1">Google AdSense <a class="header-anchor" href="#google-adsense" aria-label="Permalink to “Google AdSense”">​</a></h3><p>This site uses Google AdSense to display advertisements. Google may use cookies to show ads based on your interests.</p><ul><li><a href="https://policies.google.com/technologies/ads" target="_blank" rel="noreferrer">Google Ads Privacy Policy</a></li><li><a href="https://adssettings.google.com/" target="_blank" rel="noreferrer">How to manage Google ad settings</a></li></ul><h3 id="google-analytics-if-enabled" tabindex="-1">Google Analytics (if enabled) <a class="header-anchor" href="#google-analytics-if-enabled" aria-label="Permalink to “Google Analytics (if enabled)”">​</a></h3><p>This site may use Google Analytics to analyze website traffic.</p><ul><li><a href="https://policies.google.com/privacy" target="_blank" rel="noreferrer">Google Analytics Privacy Policy</a></li></ul><h2 id="advertising-notice" tabindex="-1">Advertising Notice <a class="header-anchor" href="#advertising-notice" aria-label="Permalink to “Advertising Notice”">​</a></h2><p>All tutorial content on this site is completely free. We display advertisements to cover server and domain costs.</p><ul><li>Advertisements are provided by Google AdSense</li><li>Ad content is automatically matched by Google based on your interests</li><li>You can manage personalized ad preferences through <a href="https://adssettings.google.com/" target="_blank" rel="noreferrer">Google Ad Settings</a></li></ul><h2 id="your-choices" tabindex="-1">Your Choices <a class="header-anchor" href="#your-choices" aria-label="Permalink to “Your Choices”">​</a></h2><h3 id="managing-cookies" tabindex="-1">Managing Cookies <a class="header-anchor" href="#managing-cookies" aria-label="Permalink to “Managing Cookies”">​</a></h3><p>You can manage or delete cookies through your browser settings:</p><ul><li><a href="https://support.google.com/chrome/answer/95647" target="_blank" rel="noreferrer">Chrome Cookie Settings</a></li><li><a href="https://support.mozilla.org/kb/cookies-information-websites-store-on-your-computer" target="_blank" rel="noreferrer">Firefox Cookie Settings</a></li><li><a href="https://support.apple.com/guide/safari/manage-cookies-sfri11471/mac" target="_blank" rel="noreferrer">Safari Cookie Settings</a></li><li><a href="https://support.microsoft.com/microsoft-edge/delete-cookies-in-microsoft-edge-63947406-40ac-c3b8-57b9-2a946a29ae09" target="_blank" rel="noreferrer">Edge Cookie Settings</a></li></ul><h3 id="opting-out-of-personalized-ads" tabindex="-1">Opting Out of Personalized Ads <a class="header-anchor" href="#opting-out-of-personalized-ads" aria-label="Permalink to “Opting Out of Personalized Ads”">​</a></h3><p>You can opt out of personalized ads through:</p><ul><li><a href="https://adssettings.google.com/" target="_blank" rel="noreferrer">Google Ad Settings</a></li><li><a href="https://optout.networkadvertising.org/" target="_blank" rel="noreferrer">Network Advertising Initiative Opt-out Page</a></li></ul><h2 id="children-s-privacy" tabindex="-1">Children&#39;s Privacy <a class="header-anchor" href="#children-s-privacy" aria-label="Permalink to “Children&#39;s Privacy”">​</a></h2><p>This site is not intended for children under 13, and we do not knowingly collect personal information from children.</p><h2 id="data-security" tabindex="-1">Data Security <a class="header-anchor" href="#data-security" aria-label="Permalink to “Data Security”">​</a></h2><p>We take reasonable technical and organizational measures to protect your information. However, please note that internet transmission cannot be 100% secure.</p><h2 id="policy-updates" tabindex="-1">Policy Updates <a class="header-anchor" href="#policy-updates" aria-label="Permalink to “Policy Updates”">​</a></h2><p>We may update this privacy policy from time to time. Updated policies will be posted on this page with an updated &quot;Last updated&quot; date.</p><h2 id="contact-us" tabindex="-1">Contact Us <a class="header-anchor" href="#contact-us" aria-label="Permalink to “Contact Us”">​</a></h2><p>If you have any questions about this privacy policy, please contact us through:</p><ul><li>GitHub Issues: <a href="https://github.com/vbgate/learn-opencode/issues" target="_blank" rel="noreferrer">https://github.com/vbgate/learn-opencode/issues</a></li><li>WeChat Group: <a href="/en/community.html">Join Community</a></li></ul><hr></div>',1)])])}const u=a(r,[["render",l]]);export{g as __pageData,u as default};
